1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type Damage = { itemType: string; amount: number };
3	type Incident = { cause?: string; damages: Damage[] };
4	type QuoteStep = { op?: "quote"; items: Item[] };
5	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
6	type Step = QuoteStep | ClaimStep;
7	type Scenario = { customer?: { yearsWithMHPCO?: number }; steps: Step[] };
8	
9	const PROCESSING_FEE = 5;
10	const COMPONENT_BASE_PER_ITEM = 25;
11	const COMPONENT_BLOCK_OF_THREE_BASE = 60;
12	
13	const CURSED_SURCHARGE_RATE = 0.5;
14	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
15	const FIRST_INSURANCE_MARKUP_RATE = 0.1;
16	const LOYALTY_DISCOUNT_RATE = 0.2;
17	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
18	const LOYALTY_YEARS_THRESHOLD = 2;
19	const HIGH_ENCHANTMENT_THRESHOLD = 5;
20	
21	const CLAIM_DEDUCTIBLE = 100;
22	const CAP_MULTIPLIER = 2;
23	
24	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
25	  sword: 100,
26	  amulet: 60,
27	  staff: 80,
28	  potion: 40,
29	};
30	
31	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
32	  sword: 1000,
33	  rune: 250,
34	};
35	
36	type PolicyState = { items: Item[]; remainingCap: number };
37	
38	export function runScenario(input: unknown): unknown {
39	  const { customer, steps } = input as Scenario;
40	  const years = customer?.yearsWithMHPCO ?? 0;
41	  const policies: Record<number, PolicyState> = {};
42	  const results = steps.map((step, index) => {
43	    if (step.op === "claim") return computeClaim(step, policies);
44	    const isFollowUp = index >= 1;
45	    const insuranceSum = step.items.reduce((s, i) => s + INSURANCE_VALUE_BY_TYPE[i.type], 0);
46	    policies[index] = { items: step.items, remainingCap: CAP_MULTIPLIER * insuranceSum };
47	    return { premium: computePremium(step.items, years, isFollowUp) };
48	  });
49	  return { results };
50	}
51	
52	function computeClaim(step: ClaimStep, policies: Record<number, PolicyState>): { payout: number; remainingCap: number } {
53	  const policy = policies[step.policy];
54	  const payout = step.incident.damages.reduce(
55	    (sum, damage) => sum + Math.max(0, damage.amount - CLAIM_DEDUCTIBLE),
56	    0,
57	  );
58	  policy.remainingCap -= payout;
59	  return { payout, remainingCap: policy.remainingCap };
60	}
61	
62	function computePremium(items: Item[], years: number, isFollowUp: boolean): number {
63	  if (items.length === 0) return PROCESSING_FEE;
64	  if (items.every(isComponent)) return componentsPremium(items);
65	  return mainItemsPremium(items, years, isFollowUp);
66	}
67	
68	function mainItemsPremium(items: Item[], years: number, isFollowUp: boolean): number {
69	  const policyBase = items.reduce((sum, item) => sum + BASE_PREMIUM_BY_TYPE[item.type], 0);
70	  const itemSubtotalSum = items.reduce((sum, item) => sum + itemSubtotal(item), 0);
71	  const policyMod = (cond: boolean, rate: number) => (cond ? policyBase * rate : 0);
72	  const loyaltyDiscount = policyMod(years >= LOYALTY_YEARS_THRESHOLD, LOYALTY_DISCOUNT_RATE);
73	  const followUpDiscount = policyMod(isFollowUp, FOLLOW_UP_DISCOUNT_RATE);
74	  return Math.ceil(itemSubtotalSum - loyaltyDiscount - followUpDiscount) + PROCESSING_FEE;
75	}
76	
77	function itemSubtotal(item: Item): number {
78	  const base = BASE_PREMIUM_BY_TYPE[item.type];
79	  const surchargeIf = (cond: boolean, rate: number) => (cond ? base * rate : 0);
80	  const cursedSurcharge = surchargeIf(item.cursed === true, CURSED_SURCHARGE_RATE);
81	  const highEnchSurcharge = surchargeIf(isHighlyEnchanted(item), HIGH_ENCHANTMENT_SURCHARGE_RATE);
82	  const firstInsuranceMarkup = base * FIRST_INSURANCE_MARKUP_RATE;
83	  return base + cursedSurcharge + highEnchSurcharge + firstInsuranceMarkup;
84	}
85	
86	function isHighlyEnchanted(item: Item): boolean {
87	  return (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
88	}
89	
90	function componentsPremium(items: Item[]): number {
91	  const runes = items.filter((i) => i.type === "rune").length;
92	  const moonstones = items.filter((i) => i.type === "moonstone").length;
93	  return premiumFromBase(componentTypeBase(runes) + componentTypeBase(moonstones));
94	}
95	
96	function componentTypeBase(count: number): number {
97	  return count === 3 ? COMPONENT_BLOCK_OF_THREE_BASE : count * COMPONENT_BASE_PER_ITEM;
98	}
99	
100	function isComponent(item: Item): boolean {
101	  return item.type === "rune" || item.type === "moonstone";
102	}
103	
104	function premiumFromBase(base: number): number {
105	  return Math.ceil((base * 11) / 10) + PROCESSING_FEE;
106	}
